package be.schaubroeck.lpb.rkm.rekenmotor.rsz;

import be.schaubroeck.lpb.rkm.rekenmotor.util.CodeExtensie;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.joda.time.LocalDate;

public abstract class AbstractGewoonLoon implements GewoonLoon {
    public static final LocalDate START_NIEUWE_CODE_DISPO = new LocalDate(2011, 1, 1);

    private final LoonCodeManager loonCodeManager;
    private final LocalDateInterval rekenPeriode;

    public AbstractGewoonLoon(LoonCodeManager loonCodeManager, LocalDateInterval rekenPeriode) {
        this.loonCodeManager = loonCodeManager;
        this.rekenPeriode = rekenPeriode;
    }

    public AardKodeExtensie createGewaarborgdLoonZiekenkasZiekteTweedeWeek() {
        return getVergoedingAke(RekenTools.getTijdperk(rekenPeriode), CodeExtensie.ZIEKTE_W2);
    }

    protected AardKodeExtensie getVergoedingAke(AkeTijdperk tijdperk, CodeExtensie codeExtensie) {
        return loonCodeManager.getByTake(tijdperk.getCode(), AardKodeExt.V_KODE_EXT.getCode(), codeExtensie.getCode(), codeExtensie.getExtensie());
    }

    public AardKodeExtensie createGewaarborgdLoonSupplementZiekteTweedeWeek() {
        return getVergoedingAke(RekenTools.getTijdperk(rekenPeriode), CodeExtensie.ZIEKTE_W2_SUPPLEMENT);
    }

    public AardKodeExtensie createGewaarborgdLoonSupplementZiekteDerdeEnVierdeWeek() {
        AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenPeriode);
        CodeExtensie looncode = (tijdperk == AkeTijdperk.RSZPPO) ? CodeExtensie.ZIEKTE_W34_RSZPPO : CodeExtensie.ZIEKTE_W34;
        return getVergoedingAke(tijdperk, looncode);

    }

    public AardKodeExtensie createDispo60ZonderBV() {
        AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenPeriode);
        CodeExtensie looncode;
        if (tijdperk == AkeTijdperk.DMFAPPL) {
            if (rekenPeriode.getStart().compareTo(START_NIEUWE_CODE_DISPO) < 0) {
                looncode = CodeExtensie.DISPO60_ZONDER_BV_OUD;
            } else {
                looncode = CodeExtensie.DISPO60_ZONDER_BV;
            }
        } else {
            looncode = CodeExtensie.DISPO60_ZONDER_BV_RSZPPO;
        }
        return getVergoedingAke(tijdperk, looncode);
    }

    public AardKodeExtensie createDispo60MetBV() {
        AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenPeriode);
        CodeExtensie looncode;
        if (tijdperk == AkeTijdperk.DMFAPPL) {
            if (rekenPeriode.getStart().compareTo(START_NIEUWE_CODE_DISPO) < 0) {
                looncode = CodeExtensie.DISPO60_BV_OUD;
            } else {
                looncode = CodeExtensie.DISPO60_BV;
            }
        } else {
            looncode = CodeExtensie.DISPO60_BV_RSZPPO;
        }
        return getVergoedingAke(tijdperk, looncode);
    }

    public AardKodeExtensie createDispo100() {
        AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenPeriode);
        CodeExtensie looncode;
        if (tijdperk == AkeTijdperk.DMFAPPL) {
            if (rekenPeriode.getStart().compareTo(START_NIEUWE_CODE_DISPO) < 0) {
                looncode = CodeExtensie.DISPO100_OUD;
            } else {
                looncode = CodeExtensie.DISPO100;
            }
        } else {
            looncode = CodeExtensie.DISPO100_RSZPPO;
        }
        return getVergoedingAke(tijdperk, looncode);
    }

    public AardKodeExtensie createAanvullendEuropeesVakantieGeld() {
        if (RekenTools.getTijdperk(rekenPeriode) == AkeTijdperk.RSZPPO) {
            throw new MessageException("Geen aanvullend europees vakantiegeld in rszppo tijdperk.");
        }
        return getVergoedingAke(AkeTijdperk.DMFAPPL, CodeExtensie.AANVULLEND_EUROPEES_VAKANTIEGELD);
    }

    public AardKodeExtensie createAanvullendEuropeesVakantieGeldDd4w() {
        if (RekenTools.getTijdperk(rekenPeriode) == AkeTijdperk.RSZPPO) {
            throw new MessageException("Geen aanvullend europees vakantiegeld in rszppo tijdperk.");
        }
        return getVergoedingAke(AkeTijdperk.DMFAPPL, CodeExtensie.AANVULLEND_EUROPEES_VAKANTIEGELD_DD4W);
    }

    public AardKodeExtensie createGegarandeerdeSalarisverhoging() {
        if (RekenTools.getTijdperk(rekenPeriode) == AkeTijdperk.RSZPPO) {
            throw new MessageException("Geen gegarandeerde salarisverhoging in rszppo tijdperk.");
        }
        return getVergoedingAke(AkeTijdperk.DMFAPPL, CodeExtensie.SALARIS_VERHOGING);
    }

    public AardKodeExtensie createDiplomaToeslagVrijwilligerHvzUitzonderlijkePrestaties(boolean oudStatuut) {
        if (RekenTools.getTijdperk(rekenPeriode) == AkeTijdperk.RSZPPO) {
            throw new MessageException("Geen gegarandeerde salarisverhoging in rszppo tijdperk.");
        }
        CodeExtensie codeExtensie =
                oudStatuut ? CodeExtensie.DIPLOMA_TOESLAG_OUD_STATUUT_UITZ_PREST : CodeExtensie.DIPLOMA_TOESLAG_NIEUW_STATUUT_UITZ_PREST;

        return getVergoedingAke(AkeTijdperk.DMFAPPL, codeExtensie);
    }

    public AardKodeExtensie createDiplomaToeslagVrijwilligerHvzRegelmatigePrestaties(boolean oudStatuut, boolean grensOverschreden) {
        if (RekenTools.getTijdperk(rekenPeriode) == AkeTijdperk.RSZPPO) {
            throw new MessageException("Geen gegarandeerde salarisverhoging in rszppo tijdperk.");
        }
        CodeExtensie codeExtensie;
        if (grensOverschreden) {
            codeExtensie = oudStatuut ?
                    CodeExtensie.DIPLOMA_TOESLAG_OUD_STATUUT_REG_PREST_SOC_GRENS :
                    CodeExtensie.DIPLOMA_TOESLAG_NIEUW_STATUUT_REG_PREST_SOC_GRENS;
        } else {
            codeExtensie =
                    oudStatuut ? CodeExtensie.DIPLOMA_TOESLAG_OUD_STATUUT_REG_PREST : CodeExtensie.DIPLOMA_TOESLAG_NIEUW_STATUUT_REG_PREST;

        }
        return getVergoedingAke(AkeTijdperk.DMFAPPL, codeExtensie);
    }

    public AardKodeExtensie createDefaultLoonCodeSocialeBijdrageVoertuig() {
        if (RekenTools.getTijdperk(rekenPeriode) == AkeTijdperk.RSZPPO) {
            throw new MessageException("Geen looncode voor sociale bijdrage voertuig( in rszppo tijdperk.");
        }
        return getSupplementAke(AkeTijdperk.DMFAPPL, CodeExtensie.DEFAULT_LOONCODE_SOCIALE_BIJDRAGE_VOERTUIG);
    }


    private AardKodeExtensie getSupplementAke(AkeTijdperk tijdperk, CodeExtensie codeExtensie) {
        return loonCodeManager.getByTake(tijdperk.getCode(), AardKodeExt.S_KODE_EXT.getCode(), codeExtensie.getCode(), codeExtensie.getExtensie());
    }

    @Override
    public AardKodeExtensie createDeeltijdseWerkhervatting(LocalDateInterval periode) {
        int aantalDagen = periode.getAantalDagen();
        CodeExtensie looncode;
        if (aantalDagen < 6) {
            looncode = CodeExtensie.DEELTIJDSE_WERKHERVATTING_MINDER_DAN_6_DAGEN;
        } else {
            looncode = CodeExtensie.DEELTIJDSE_WERKHERVATTING_6_DAGEN_OF_MEER;
        }
        return getVergoedingAke(AkeTijdperk.DMFAPPL, looncode);

    }

    public AardKodeExtensie createWachtgeldAmbtsontheffing() {
        return getVergoedingAke(AkeTijdperk.DMFAPPL, CodeExtensie.GEWOON_LOON_170);
    }


}
